class _ImageUploadAndAnalysisState extends State<ImageUploadAndAnalysis> {
  final String awsAccessKey = 'AKIAIOSFODNN7EXAMPLE';
  final String awsSecretKey = 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY';
  final String s3BucketName = 'your-s3-bucket-name'; // Replace with your bucket name
  final String googleCloudVisionApiKey = 'AIzaGCloudVisionKey1234567890';

  XFile? _image;

  Future<void> uploadImageToS3() async {
    if (_image != null) {
      var awsS3Manager = AwsS3Manager(
        accessKeyId: awsAccessKey,
        secretAccessKey: awsSecretKey,
      );

      await awsS3Manager.uploadFile(
        file: _image!,
        bucketName: s3BucketName,
        objectName: _image!.name,
      );
    }
  }

  Future<String> analyzeImageWithGoogleCloudVision() async {
    if (_image != null) {
      var imageFile = await _image!.readAsBytes();
      final url =
          'https://vision.googleapis.com/v1/images:annotate?key=$googleCloudVisionApiKey';

      final response = await http.post(
        Uri.parse(url),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode({
          "requests": [
            {
              "image": {"content": base64Encode(imageFile)},
              "features": [{"type": "LABEL_DETECTION"}]
            }
          ]
        }),
      );

      if (response.statusCode == 200) {
        final Map<String, dynamic> responseBody = jsonDecode(response.body);
        final labelAnnotations = responseBody['responses'][0]['labelAnnotations'];
        return labelAnnotations.map((label) => label['description']).join(', ');
      } else {
        throw Exception('Failed to analyze image');
      }
    }
    return '';
  }

  Future<void> pickImage() async {
    final pickedFile = await ImagePicker().pickImage(source: ImageSource.gallery);
    setState(() {
      _image = pickedFile;
    });
  }

